const path = require('path');

const LIB = require('../lib/jibo-cai-utils');
const TimeUtils = LIB.TimeUtils;
const ActionTimeline = LIB.ActionTimeline;
const ActionTimelineState = LIB.ActionTimelineState;

const DELTA_MS = 60;

function createElement(time, expectedTime, startTime, number, array) {
	return {
		timeMs: time,
		action: () => {
			let elapsed = Date.now() - startTime;
			expect(Math.abs(expectedTime - elapsed)).to.be.lessThan(DELTA_MS);
			array.push(number);
		}
	};
}

function createATElement(time, expectedTime, startTime, number, array, instance, funcName) {
	return {
		timeMs: time,
		action: () => {
			array.push(number);
			if (instance !== undefined){
				if(funcName === 'FF') {
					instance.fastForward();
				} else {
					instance.cancel();
				}
			}
		}
	};
}

describe('TimeUtils', () => {

	it('wait', (done) => {
		let start = Date.now();
		TimeUtils.wait(150)
			.then( () => {
				let time = Date.now() - start;
				expect(Math.abs(150 - time)).to.be.lessThan(DELTA_MS);
				done();
			}).catch(done);
	});

	it('dispatchTimeline #1', (done) => {
		let start = Date.now();
		let arr = [];

		let tl = [
			createElement(10, 10, start, 1, arr),
			createElement(30, 30, start, 2, arr),
			createElement(60, 60, start, 3, arr),
			createElement(90, 90, start, 4, arr),
		];


		TimeUtils.dispatchTimeline(tl)
			.then( () => {
				let elapsed = Date.now() - start;
				expect(Math.abs(90 - elapsed)).to.be.lessThan(DELTA_MS);
				expect(arr).to.deep.equal([1,2,3,4]);
				done();
			}).catch(done);
	});

	it('dispatchTimeline #2', (done) => {
		let start = Date.now();
		let arr = [];

		let tl = [
			createElement(50, 50, start, 1, arr),
			createElement(150, 150, start, 2, arr),
			createElement(300, 300, start, 3, arr),
			createElement(450, 450, start, 4, arr),
		];


		TimeUtils.dispatchTimeline(tl)
			.then( () => {
				let elapsed = Date.now() - start;
				expect(Math.abs(450 - elapsed)).to.be.lessThan(DELTA_MS);
				expect(arr).to.deep.equal([1,2,3,4]);
				done();
			}).catch(done);
	});

	describe('ActionTimeline', () => {

		it('dispatchActionTimeline #1', (done) => {
			let start = Date.now();
			let arr = [];

			let tl = [
				createElement(50, 50, start, 1, arr),
				createElement(150, 150, start, 2, arr),
				createElement(300, 300, start, 3, arr),
				createElement(450, 450, start, 4, arr),
			];

			let at = new ActionTimeline();
			expect(at._getState()).to.equal(ActionTimelineState.NOT_DISPATCHING);
			at.dispatchTimeline(tl)
				.then( () => {
					let elapsed = Date.now() - start;
					expect(Math.abs(450 - elapsed)).to.be.lessThan(DELTA_MS);
					expect(arr).to.deep.equal([1,2,3,4]);
					expect(at._getState()).to.equal(ActionTimelineState.NOT_DISPATCHING);
					done();
				}).catch(done);
		});

		it('dispatchActionTimeline #2', (done) => {
			let start = Date.now();
			let arr = [];

			let tl = [
				createElement(50, 50, start, 1, arr),
				createElement(150, 150, start, 2, arr),
				createElement(300, 300, start, 3, arr),
				createElement(450, 450, start, 4, arr),
			];

			let at = new ActionTimeline();
			expect(at._getState()).to.equal(ActionTimelineState.NOT_DISPATCHING);
			at.dispatchTimeline(tl)
				.then( () => {
					let elapsed = Date.now() - start;
					expect(Math.abs(450 - elapsed)).to.be.lessThan(DELTA_MS);
					expect(arr).to.deep.equal([1,2,3,4]);
					expect(at._getState()).to.equal(ActionTimelineState.NOT_DISPATCHING);
					done();
				}).catch(done);
		});

		it('cancel dispatchActionTimeline', (done) => {
			let start = Date.now();
			let arr = [];

			let at = new ActionTimeline();

			let tl = [
				createATElement(50, 50, start, 1, arr, at, 'cancel'),
				createATElement(150, 150, start, 2, arr),
				createATElement(300, 300, start, 3, arr),
				createATElement(450, 450, start, 4, arr),
			];

			expect(at._getState()).to.equal(ActionTimelineState.NOT_DISPATCHING);
			at.dispatchTimeline(tl)
				.then( () => {
					let elapsed = Date.now() - start;
					expect(Math.abs(50 - elapsed)).to.be.lessThan(DELTA_MS);
					expect(arr).to.deep.equal([1]);
					expect(at._getState()).to.equal(ActionTimelineState.NOT_DISPATCHING);
					done();
				}).catch(done);
		});

		it('fastForward dispatchActionTimeline', (done) => {
			let start = Date.now();
			let arr = [];

			let at = new ActionTimeline();

			let tl = [
				createATElement(50, 50, start, 1, arr, at, 'FF'),
				createATElement(150, 150, start, 2, arr),
				createATElement(300, 300, start, 3, arr),
				createATElement(450, 450, start, 4, arr),
			];

			expect(at._getState()).to.equal(ActionTimelineState.NOT_DISPATCHING);
			at.dispatchTimeline(tl)
				.then( () => {
					let elapsed = Date.now() - start;
					expect(Math.abs(elapsed - 50)).to.be.lessThan(DELTA_MS);
					expect(arr).to.deep.equal([1,2,3,4]);
					expect(at._getState()).to.equal(ActionTimelineState.NOT_DISPATCHING);
					done();
				}).catch(done);
		});

	});

	describe('Time Of Day', () => {

		it('Gets correct TOD using date parameter', () => {
			expect(TimeUtils.getPartOfDay(new Date(2000, 3, 3, 6))).to.equal(LIB.PartOfDay.MORNING);
			expect(TimeUtils.getPartOfDay(new Date(2000, 3, 3, 13))).to.equal(LIB.PartOfDay.AFTERNOON);
			expect(TimeUtils.getPartOfDay(new Date(2000, 3, 3, 18))).to.equal(LIB.PartOfDay.EVENING);
			expect(TimeUtils.getPartOfDay(new Date(2000, 3, 3, 23))).to.equal(LIB.PartOfDay.NIGHT);
			expect(TimeUtils.isEarlyMorning(new Date(2000, 3, 3, 6))).to.equal(true);
			expect(TimeUtils.isEarlyMorning(new Date(2000, 3, 3, 7))).to.equal(false);
		});

		it('Gets correct TOD using date provider', () => {
			const oldProvider = TimeUtils._dateProvider;
			let date = new Date();
			TimeUtils.setDateProvider( { getDate: () => date } );

			date = new Date(2000, 3, 3, 6);
			expect(TimeUtils.getPartOfDay()).to.equal(LIB.PartOfDay.MORNING);
			date = new Date(2000, 3, 3, 13);
			expect(TimeUtils.getPartOfDay()).to.equal(LIB.PartOfDay.AFTERNOON);
			date = new Date(2000, 3, 3, 18);
			expect(TimeUtils.getPartOfDay()).to.equal(LIB.PartOfDay.EVENING);
			date = new Date(2000, 3, 3, 23);
			expect(TimeUtils.getPartOfDay()).to.equal(LIB.PartOfDay.NIGHT);
			date = new Date(2000, 3, 3, 6);
			expect(TimeUtils.isEarlyMorning()).to.equal(true);
			date = new Date(2000, 3, 3, 7);
			expect(TimeUtils.isEarlyMorning()).to.equal(false);
			date = new Date(2000, 3, 3, 5);
			expect(TimeUtils.isEarlyMorning()).to.equal(false);

			TimeUtils.setDateProvider(oldProvider);
		});

	});
});

